mapper.insert:
INSERT INTO event.refunds(
     payment_seq
    ,amount
    ,currency
    ,reason
    ,status
    ,refund_type
    ,refund_request_id
    ,settle_amount
    ,pg_refund_id
    ,pg_refund_transaction_id
    ,pg_response_code
    ,pg_response_message
    ,balance_before
    ,balance_after
    ,raw_request
    ,raw_response
    ,failed_reason
    ,requested_by
    ,processed_by
    ,requested_at
    ,processed_at
    ,created_by
    ,updated_by
) VALUES (
     #{paymentSeq}
    ,#{amount}
    ,#{currency,jdbcType=VARCHAR}
    ,#{reason}
    ,#{status}
    ,#{refundType}
    ,#{refundRequestId,jdbcType=VARCHAR}
    ,#{settleAmount}
    ,#{pgRefundId,jdbcType=VARCHAR}
    ,#{pgRefundTransactionId,jdbcType=VARCHAR}
    ,#{pgResponseCode,jdbcType=VARCHAR}
    ,#{pgResponseMessage,jdbcType=VARCHAR}
    ,#{balanceBefore,jdbcType=NUMERIC}
    ,#{balanceAfter,jdbcType=NUMERIC}
    ,CAST(#{rawRequest,jdbcType=VARCHAR} AS JSONB)
    ,CAST(#{rawResponse,jdbcType=VARCHAR} AS JSONB)
    ,#{failedReason,jdbcType=VARCHAR}
    ,#{requestedBy}
    ,#{processedBy}
    ,COALESCE(#{requestedAt}, now())
    ,#{processedAt}
    ,#{createdBy}
    ,#{updatedBy}
)
